#include<bits/stdc++.h>
using namespace std;

const int N = 5e3 + 5, M = 5e5 + 5, MOD = 80112002;
int n, m, ans = 0;
vector<int> e[M];
int in[N], topo[N], dp[N], out[N], In[N];

bool toposort()
{
	int t = 0;
	queue<int> q;
	for(int i = 1; i <= n; i++)
		if(!in[i]) q.push(i);
	while(!q.empty())
	{
		int u = q.front();
		q.pop();
		topo[++t] = u;
		for(int v : e[u])
		{
			in[v]--;
			if(!in[v]) q.push(v);
		}
	}
	return t == n;
}

int main()
{
	cin >> n >> m;
	for(int i = 1; i <= m; i++)
	{
		int u, v;
		cin >> u >> v;
		e[u].push_back(v);
		in[v]++;
		In[v]++;
		out[u]++;
	}
	toposort();
	for(int i = 1; i <= n; i++)
		if(out[i] == 0) dp[i] = 1;
	for(int i = n; i >= 1; i--)
	{
		int u = topo[i];
		for(int v : e[u])
			dp[u] += dp[v], dp[u] %= MOD;
		if(!In[u]) ans += dp[u], ans %= MOD;
	}
	cout << ans;
	return 0;
}
